import React, { useState, useEffect } from "react";
import axios from "axios";

const Schemes = () => {
    const [schemes, setSchemes] = useState([]);
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState("");
    const [color, setColor] = useState("green"); // Initial button color

    const changeColor = () => {
        setColor(prev => (prev === "green" ? "red" : "green"));
    };

    useEffect(() => {
        fetchSchemes();
    }, []);

    const fetchSchemes = async () => {
        setLoading(true);
        try {
            const response = await axios.get("http://localhost:5000/api/schemes/getSchemes");
            const cleanedSchemes = response.data.map(scheme => ({
                ...scheme,
                title: scheme.title.replace(/\s+/g, ' ').trim()
            }));
            setSchemes(cleanedSchemes);
        } catch (err) {
            setError("Failed to fetch schemes.");
        } finally {
            setLoading(false);
        }
    };

    return (
        <div style={{ 
            minHeight: "100vh", 
            width: "100%", 
            backgroundColor: "#FAEBCD", 
            display: "flex", 
            justifyContent: "center", 
            alignItems: "center",
            padding: "20px"
        }}>
            <div style={{ maxWidth: "800px", width: "100%", textAlign: "center" }}>
                <h2 style={{ marginBottom: "20px" }}>Available Schemes</h2>
                {loading && <p>Loading...</p>}
                {error && <p style={{ color: "red" }}>{error}</p>}
                
                {schemes.length === 0 ? <p>No schemes available.</p> : (
                    <div>
                        {schemes.map((scheme, index) => (
                            <div key={index} style={{ 
                                border: "1px solid #ddd", 
                                borderRadius: "8px", 
                                padding: "20px", 
                                marginBottom: "20px", 
                                background: "#f9f9f9"
                            }}>
                                <h3 style={{ color: "black", fontWeight: "bold", marginBottom: "10px" }}>{scheme.title}</h3>
                                <p style={{ marginBottom: "15px" }}>{scheme.description}</p>
                                <button 
                                    onClick={changeColor} 
                                    style={{ 
                                        backgroundColor: color, 
                                        color: "white", 
                                        padding: "5px 10px", 
                                        border: "none", 
                                        borderRadius: "5px", 
                                        cursor: "pointer" 
                                    }}>
                                    Request Scheme
                                </button>
                            </div>
                        ))}
                    </div>
                )}
            </div>
        </div>
    );
};

export default Schemes;
